module top_module(
    input  wire        CLK,
    input  wire        RST,
    input  wire        EN,
    output wire [3:0]  Q
);reg [3:0] unused_count;

    always @(posedge CLK) begin
        if (RST) begin
            unused_count <= 4'b0;
        end
        else if (EN) begin
            unused_count <= unused_count + 1;
        end
    end

    assign Q = unused_count;

endmodule
